import{_ as a,c as e,a3 as i,o as t}from"./chunks/framework.VX8o9GSp.js";const h=JSON.parse('{"title":"git commit message 规范","description":"","frontmatter":{"prev":false,"next":false,"date":"2024-06-01T00:00:00.000Z","tags":["git"],"categories":["计算机"]},"headers":[],"relativePath":"2024/06/git_commit_message_standard.md","filePath":"2024/06/git_commit_message_standard.md","lastUpdated":1729088505000}'),n={name:"2024/06/git_commit_message_standard.md"};function p(l,s,o,d,c,r){return t(),e("div",null,s[0]||(s[0]=[i(`<h1 id="git-commit-message-规范" tabindex="-1">git commit message 规范 <a class="header-anchor" href="#git-commit-message-规范" aria-label="Permalink to &quot;git commit message 规范&quot;">​</a></h1><p>在 Git 中，提交信息的规范非常重要，因为它可以帮助其他开发者了解每次提交的目的。以下是一种常见的提交信息规范：</p><ol><li><p><code>type</code>: 提交的类型，例如：feat(新功能)、fix(修复 bug)、docs(文档改变)、style(格式或者结构改变)、refactor(代码重构)、test(测试代码)、chore(构建过程或辅助工具的变动)。</p></li><li><p><code>scope</code>: 表示影响的范围，例如：数据层、控制层、视图层等。</p></li><li><p><code>subject</code>: 提交的简短描述。</p></li><li><p><code>body</code>: 提交的详细描述，可以分为多行。</p></li><li><p><code>footer</code>: 关联的问题编号，例如： #123 , #456 。</p></li></ol><p>以下是一个示例：</p><div class="language-git vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">git</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>feat(user): add login function</span></span>
<span class="line"><span></span></span>
<span class="line"><span>This commit adds a new login function to the user module. The function takes a username and password and checks them against the database.</span></span>
<span class="line"><span></span></span>
<span class="line"><span>Related to #123, #456</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br></div></div><p>在命令行中，你可以使用以下命令进行提交：</p><div class="language-bash vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">git</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> commit</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -m</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;feat(user): add login function&quot;</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -m</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;This commit adds a new login function to the user module. The function takes a username and password and checks them against the database.&quot;</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -m</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;Related to #123, #456&quot;</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>这种规范可以帮助你和你的团队更好地理解每次提交的目的和影响。</p>`,8)]))}const g=a(n,[["render",p]]);export{h as __pageData,g as default};
